INSERT INTO `quiz_questions` VALUES
('QF0001','vivant_classification',1,'Combien de pattes possède un insecte adulte ?','Six','Huit','Quatre','Dix',NULL,'A','Six','college',1,'⭐ Facile','Exact ! Tous les insectes adultes ont six pattes et un corps en trois parties (tête, thorax, abdomen).','Exact ! Tous les insectes adultes ont six pattes et un corps en trois parties (tête, thorax, abdomen).','Huit pattes, c\'est une araignée : ce n\'est pas un insecte mais un arachnide.',NULL,NULL,NULL,NULL,'insecte, classification, pattes',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0002','vivant_classification',2,'L\'araignée (comme l\'argiope du jardin) est-elle un insecte ?','Non, c\'est un arachnide à huit pattes','Oui, c\'est un insecte','Oui, car elle a des ailes','Non, c\'est un ver',NULL,'A','Non, c\'est un arachnide à huit pattes','college',1,'⭐ Facile','Bravo ! L\'araignée a huit pattes et deux parties au corps : c\'est un arachnide, pas un insecte.','Bravo ! L\'araignée a huit pattes et deux parties au corps : c\'est un arachnide, pas un insecte.','Attention à l\'erreur classique : l\'araignée n\'est pas un insecte (qui aurait 6 pattes), c\'est un arachnide.',NULL,NULL,NULL,NULL,'araignée, arachnide, insecte, classification',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0003','vivant_classification',3,'À quel groupe d\'êtres vivants appartiennent Nitrosomonas et Nitrobacter ?','Aux bactéries','Aux champignons','Aux animaux','Aux plantes',NULL,'A','Aux bactéries','college',2,'⭐⭐ Moyen','Oui ! Ce sont des bactéries, des micro-organismes formés d\'une seule cellule, invisibles à l\'œil nu.','Oui ! Ce sont des bactéries, des micro-organismes formés d\'une seule cellule, invisibles à l\'œil nu.',NULL,NULL,'Ce ne sont pas des plantes : elles ne font pas de photosynthèse. Ce sont des bactéries.',NULL,NULL,'bactérie, micro-organisme, classification',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0004','vivant_classification',4,'Le ver de terre est un…','ver (invertébré sans pattes)','insecte','mille-pattes','petit serpent',NULL,'A','ver (invertébré sans pattes)','college',1,'⭐ Facile','Exact ! Le ver de terre est un invertébré au corps mou, sans pattes ni squelette interne.','Exact ! Le ver de terre est un invertébré au corps mou, sans pattes ni squelette interne.','Un insecte a six pattes ; le ver de terre n\'a pas de pattes du tout.',NULL,NULL,NULL,NULL,'ver, invertébré, sol',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0010','ecologie_reseaux',1,'Par quoi commence toujours une chaîne alimentaire ?','Par un producteur (une plante)','Par un prédateur','Par un décomposeur','Par un herbivore',NULL,'A','Par un producteur (une plante)','college',2,'⭐⭐ Moyen','Oui ! Les plantes (producteurs) fabriquent leur matière par photosynthèse : elles sont à la base de tout.','Oui ! Les plantes (producteurs) fabriquent leur matière par photosynthèse : elles sont à la base de tout.','Le prédateur est en haut de la chaîne, pas au début. Tout commence par un producteur.',NULL,NULL,NULL,NULL,'chaîne alimentaire, producteur, photosynthèse',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0011','ecologie_reseaux',2,'Quel est le rôle des décomposeurs (vers, cloportes, bactéries) ?','Recycler la matière morte en éléments pour les plantes','Polliniser les fleurs','Chasser les ravageurs','Produire de l\'oxygène',NULL,'A','Recycler la matière morte en éléments pour les plantes','college',2,'⭐⭐ Moyen','Exact ! Les décomposeurs transforment feuilles mortes et déchets en humus et minéraux : ils bouclent le cycle.','Exact ! Les décomposeurs transforment feuilles mortes et déchets en humus et minéraux : ils bouclent le cycle.','La pollinisation, c\'est le rôle des abeilles. Les décomposeurs, eux, recyclent la matière morte.',NULL,NULL,NULL,NULL,'décomposeur, recyclage, sol',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0012','ecologie_reseaux',3,'Dans une chaîne alimentaire, que devient l\'énergie disponible quand on monte d\'un niveau au suivant ?','Elle diminue fortement (environ 10 % passe)','Elle augmente','Elle reste identique','Elle double',NULL,'A','Elle diminue fortement (environ 10 % passe)','lycee',3,'⭐⭐⭐ Difficile','Bravo ! À chaque maillon, ~90 % de l\'énergie est perdue (chaleur, respiration). C\'est pourquoi les chaînes sont courtes.','Bravo ! À chaque maillon, ~90 % de l\'énergie est perdue (chaleur, respiration). C\'est pourquoi les chaînes sont courtes.','C\'est l\'inverse : l\'énergie diminue à chaque niveau, elle n\'augmente jamais.',NULL,NULL,NULL,NULL,'niveau trophique, énergie, rendement écologique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0013','ecologie_reseaux',4,'Un animal qui se nourrit uniquement de plantes est un…','herbivore','carnivore','décomposeur','producteur',NULL,'A','herbivore','college',1,'⭐ Facile','Oui ! L\'herbivore mange des feuilles, des tiges ou de la sève, comme le puceron ou la chenille.','Oui ! L\'herbivore mange des feuilles, des tiges ou de la sève, comme le puceron ou la chenille.',NULL,NULL,'Un producteur, c\'est une plante. L\'animal qui mange les plantes est un herbivore.',NULL,NULL,'herbivore, régime alimentaire, consommateur',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0014','ecologie_reseaux',5,'Quelle est la différence entre une chaîne et un réseau trophique ?','Le réseau relie plusieurs chaînes alimentaires entre elles','Il n\'y a aucune différence','La chaîne est plus longue que le réseau','Le réseau ne concerne que les plantes',NULL,'A','Le réseau relie plusieurs chaînes alimentaires entre elles','lycee',2,'⭐⭐ Moyen','Exact ! Dans la réalité, une espèce a plusieurs proies et prédateurs : les chaînes s\'entremêlent en un réseau trophique.','Exact ! Dans la réalité, une espèce a plusieurs proies et prédateurs : les chaînes s\'entremêlent en un réseau trophique.','Il y a bien une différence : le réseau trophique est l\'ensemble des chaînes reliées entre elles.',NULL,NULL,NULL,NULL,'réseau trophique, chaîne alimentaire',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0020','cycle_azote_aquaponie',1,'En aquaponie, d\'où vient l\'ammonium présent dans l\'eau ?','Des déjections des poissons','De la lumière','Des racines des plantes','De l\'air pompé dans l\'eau',NULL,'A','Des déjections des poissons','college',2,'⭐⭐ Moyen','Exact ! Les poissons rejettent de l\'ammonium, qui serait toxique sans les bactéries pour le transformer.','Exact ! Les poissons rejettent de l\'ammonium, qui serait toxique sans les bactéries pour le transformer.',NULL,'Les racines absorbent les nitrates ; elles ne produisent pas l\'ammonium. Celui-ci vient des poissons.',NULL,NULL,NULL,'aquaponie, ammonium, poissons',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0021','cycle_azote_aquaponie',2,'Quel est le rôle des plantes dans un système d\'aquaponie ?','Absorber les nitrates et épurer l\'eau','Produire l\'ammonium','Manger les poissons','Réchauffer l\'eau',NULL,'A','Absorber les nitrates et épurer l\'eau','college',2,'⭐⭐ Moyen','Oui ! En absorbant les nitrates, les plantes nettoient l\'eau qui retourne propre aux poissons. La boucle est bouclée.','Oui ! En absorbant les nitrates, les plantes nettoient l\'eau qui retourne propre aux poissons. La boucle est bouclée.','Ce sont les poissons qui produisent l\'ammonium ; les plantes, elles, consomment les nitrates.',NULL,NULL,NULL,NULL,'aquaponie, nitrate, plantes, épuration',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0022','cycle_azote_aquaponie',3,'Dans la nitrification, quelle bactérie transforme l\'ammonium en nitrites ?','Nitrosomonas','Nitrobacter','Nitrospira','Aucune, c\'est une plante',NULL,'A','Nitrosomonas','lycee',3,'⭐⭐⭐ Difficile','Bravo ! Nitrosomonas oxyde l\'ammonium en nitrites ; ensuite Nitrobacter et Nitrospira transforment les nitrites en nitrates.','Bravo ! Nitrosomonas oxyde l\'ammonium en nitrites ; ensuite Nitrobacter et Nitrospira transforment les nitrites en nitrates.','Nitrobacter intervient à la 2ᵉ étape (nitrites → nitrates). La 1ʳᵉ étape (ammonium → nitrites) est faite par Nitrosomonas.',NULL,NULL,NULL,NULL,'nitrification, ammonium, nitrites, bactérie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0023','cycle_azote_aquaponie',4,'Pourquoi dit-on que l\'azote « circule en boucle » dans le jardin et l\'aquaponie ?','Un déchet (ammonium) redevient un engrais (nitrate) réutilisable','Parce que l\'eau tourne dans un tuyau','Parce que les poissons nagent en rond','L\'azote ne circule pas, il disparaît',NULL,'A','Un déchet (ammonium) redevient un engrais (nitrate) réutilisable','lycee',2,'⭐⭐ Moyen','Exact ! La matière se recycle : l\'azote passe des déchets aux bactéries puis aux plantes, sans se perdre. C\'est un cycle biogéochimique.','Exact ! La matière se recycle : l\'azote passe des déchets aux bactéries puis aux plantes, sans se perdre. C\'est un cycle biogéochimique.',NULL,NULL,'Au contraire, l\'azote ne disparaît pas : il est recyclé en boucle entre êtres vivants et milieu.',NULL,NULL,'cycle de l\'azote, nitrate, recyclage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0024','cycle_azote_aquaponie',5,'Que fait la dénitrification dans le cycle de l\'azote ?','Elle renvoie l\'azote des nitrates vers l\'atmosphère sous forme de gaz','Elle fabrique de l\'ammonium','Elle produit de l\'oxygène','Elle tue les poissons',NULL,'A','Elle renvoie l\'azote des nitrates vers l\'atmosphère sous forme de gaz','lycee',3,'⭐⭐⭐ Difficile','Bravo ! En milieu peu oxygéné, des bactéries transforment les nitrates en azote gazeux : c\'est l\'étape qui ferme le cycle.','Bravo ! En milieu peu oxygéné, des bactéries transforment les nitrates en azote gazeux : c\'est l\'étape qui ferme le cycle.','L\'ammonium provient de l\'ammonification (déchets) ; la dénitrification, elle, renvoie l\'azote vers l\'air.',NULL,NULL,NULL,NULL,'dénitrification, cycle de l\'azote, nitrate',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0025','cycle_azote_aquaponie',6,'Que contiennent les nodosités sur les racines de la fève ou du haricot ?','Des bactéries qui fixent l\'azote de l\'air','Des œufs d\'insectes','De l\'eau de réserve','Du sucre',NULL,'A','Des bactéries qui fixent l\'azote de l\'air','lycee',3,'⭐⭐⭐ Difficile','Exact ! Les bactéries Rhizobium logées dans les nodosités fixent l\'azote atmosphérique : c\'est pourquoi les légumineuses enrichissent le sol.','Exact ! Les bactéries Rhizobium logées dans les nodosités fixent l\'azote atmosphérique : c\'est pourquoi les légumineuses enrichissent le sol.','Ce ne sont pas des œufs : les nodosités abritent des bactéries fixatrices d\'azote, en symbiose avec la plante.',NULL,NULL,NULL,NULL,'nodosité, fixation de l\'azote, symbiose, légumineuse',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0030','sol_compost',1,'Que devient un tas de compost réussi au bout de plusieurs mois ?','Un terreau sombre et friable (humus) qui nourrit le sol','Du plastique','De la cendre','Rien, tout disparaît',NULL,'A','Un terreau sombre et friable (humus) qui nourrit le sol','college',1,'⭐ Facile','Oui ! Les décomposeurs transforment les déchets en humus, un engrais naturel sombre et friable.','Oui ! Les décomposeurs transforment les déchets en humus, un engrais naturel sombre et friable.',NULL,NULL,'La matière ne disparaît pas : elle est transformée en humus, riche pour le jardin.',NULL,NULL,'compostage, humus, sol',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0031','sol_compost',2,'Idée reçue : le ver de terre mange-t-il les racines des plantes ?','Non, il mange surtout de la matière organique morte','Oui, il dévore les racines','Oui, mais seulement la nuit','Non, il ne mange rien',NULL,'A','Non, il mange surtout de la matière organique morte','college',2,'⭐⭐ Moyen','Exact ! Le ver de terre avale terre et débris morts ; il aère le sol et l\'enrichit. C\'est un allié, pas un ravageur.','Exact ! Le ver de terre avale terre et débris morts ; il aère le sol et l\'enrichit. C\'est un allié, pas un ravageur.','Erreur fréquente ! Le ver de terre ne s\'attaque pas aux racines vivantes : il recycle la matière morte.',NULL,NULL,NULL,NULL,'ver de terre, détritivore, sol vivant',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0032','sol_compost',3,'Pourquoi un compost peut-il se mettre à sentir mauvais ?','Il est trop tassé et trop humide : il fermente sans oxygène','Il contient trop de feuilles sèches','Il est trop aéré','Il est trop froid',NULL,'A','Il est trop tassé et trop humide : il fermente sans oxygène','lycee',2,'⭐⭐ Moyen','Oui ! Sans oxygène, la fermentation produit de mauvaises odeurs. Il faut aérer et équilibrer déchets verts et bruns.','Oui ! Sans oxygène, la fermentation produit de mauvaises odeurs. Il faut aérer et équilibrer déchets verts et bruns.','Trop de matières sèches ralentit le compost mais ne le fait pas pourrir. L\'odeur vient surtout du manque d\'air et de l\'excès d\'eau.',NULL,NULL,NULL,NULL,'compost, fermentation, oxygène',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0033','sol_compost',4,'Qu\'est-ce qu\'un « sol vivant » ?','Un sol riche en organismes qui le rendent fertile','Un sol qui bouge tout seul','Un sol sans aucun être vivant','Un sol entièrement minéral',NULL,'A','Un sol riche en organismes qui le rendent fertile','college',1,'⭐ Facile','Bravo ! Bactéries, champignons, vers et insectes y travaillent la matière organique et nourrissent les plantes.','Bravo ! Bactéries, champignons, vers et insectes y travaillent la matière organique et nourrissent les plantes.',NULL,'C\'est le contraire : un sol vivant grouille d\'organismes, c\'est ce qui le rend fertile.',NULL,NULL,NULL,'sol vivant, biodiversité, fertilité',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0033b','sol_compost',5,'Qu\'est-ce que la minéralisation de la matière organique ?','La libération de sels minéraux assimilables par les plantes','La transformation en pierre','La fabrication de plastique','Le dessèchement du sol',NULL,'A','La libération de sels minéraux assimilables par les plantes','lycee',3,'⭐⭐⭐ Difficile','Oui ! En fin de décomposition, les décomposeurs libèrent les sels minéraux (azote, phosphore…) que les plantes réabsorbent.','Oui ! En fin de décomposition, les décomposeurs libèrent les sels minéraux (azote, phosphore…) que les plantes réabsorbent.','« Minéralisation » ne veut pas dire transformation en pierre : c\'est la libération de sels minéraux par les décomposeurs.',NULL,NULL,NULL,NULL,'minéralisation, décomposeur, sels minéraux',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0034b','sol_compost',6,'Qu\'est-ce qu\'une mycorhize ?','Une association entre un champignon et les racines d\'une plante','Une maladie des racines','Un engrais chimique','Un type de ver',NULL,'A','Une association entre un champignon et les racines d\'une plante','lycee',3,'⭐⭐⭐ Difficile','Bravo ! Le champignon étend la zone d\'absorption de la plante (eau, phosphore) et reçoit des sucres : une symbiose très répandue.','Bravo ! Le champignon étend la zone d\'absorption de la plante (eau, phosphore) et reçoit des sucres : une symbiose très répandue.','Ce n\'est pas une maladie : la mycorhize est une symbiose bénéfique entre champignon et racines.',NULL,NULL,NULL,NULL,'mycorhize, symbiose, sol',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0040','plantes_biologie',1,'Dans quelle partie de la plante se déroule surtout la photosynthèse ?','Les feuilles','Les racines','Les fleurs','Les graines',NULL,'A','Les feuilles','college',1,'⭐ Facile','Oui ! Grâce à la chlorophylle des feuilles, la plante capte la lumière pour fabriquer sa nourriture.','Oui ! Grâce à la chlorophylle des feuilles, la plante capte la lumière pour fabriquer sa nourriture.','Les racines absorbent l\'eau et les minéraux, mais la photosynthèse se fait dans les feuilles (vertes).',NULL,NULL,NULL,NULL,'photosynthèse, feuille, chlorophylle',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0041','plantes_biologie',2,'Le jour, que rejette une plante quand elle fait la photosynthèse ?','Du dioxygène','Du dioxyde de carbone uniquement','De l\'azote','Rien',NULL,'A','Du dioxygène','college',2,'⭐⭐ Moyen','Exact ! La plante absorbe le CO2 et rejette du dioxygène : elle participe à renouveler l\'air que nous respirons.','Exact ! La plante absorbe le CO2 et rejette du dioxygène : elle participe à renouveler l\'air que nous respirons.','La plante absorbe le CO2 pour la photosynthèse ; elle rejette du dioxygène le jour.',NULL,NULL,NULL,NULL,'photosynthèse, dioxygène, CO2',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0042','plantes_biologie',3,'Au sens botanique (scientifique), la tomate est…','un fruit (il contient les graines)','un légume-racine','une fleur','une graine',NULL,'A','un fruit (il contient les graines)','lycee',2,'⭐⭐ Moyen','Bravo ! Botaniquement, le fruit se forme après la fleur et contient les graines : la tomate est donc un fruit.','Bravo ! Botaniquement, le fruit se forme après la fleur et contient les graines : la tomate est donc un fruit.','On la cuisine comme un légume, mais comme elle contient les graines, c\'est un fruit au sens botanique.',NULL,NULL,NULL,NULL,'fruit, fleur, botanique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0043','plantes_biologie',4,'De quoi une plante a-t-elle besoin pour réaliser la photosynthèse ?','De lumière, d\'eau et de dioxyde de carbone','De viande et d\'eau','D\'obscurité totale','D\'azote uniquement',NULL,'A','De lumière, d\'eau et de dioxyde de carbone','lycee',2,'⭐⭐ Moyen','Oui ! Avec la lumière, l\'eau et le CO2, la plante fabrique des sucres et rejette du dioxygène.','Oui ! Avec la lumière, l\'eau et le CO2, la plante fabrique des sucres et rejette du dioxygène.',NULL,'Sans lumière, pas de photosynthèse : c\'est justement l\'énergie lumineuse qui permet la réaction.',NULL,NULL,NULL,'photosynthèse, lumière, eau, CO2',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0044b','plantes_biologie',5,'Une plante respire-t-elle ?','Oui, elle respire jour et nuit','Non, elle ne fait que la photosynthèse','Seulement la nuit, jamais le jour','Non, les plantes ne respirent pas',NULL,'A','Oui, elle respire jour et nuit','lycee',2,'⭐⭐ Moyen','Exact ! La plante respire en permanence (elle consomme de l\'O2). Le jour, la photosynthèse masque sa respiration car elle produit plus d\'O2 qu\'elle n\'en consomme.','Exact ! La plante respire en permanence (elle consomme de l\'O2). Le jour, la photosynthèse masque sa respiration car elle produit plus d\'O2 qu\'elle n\'en consomme.',NULL,NULL,'Idée reçue : comme tous les êtres vivants, la plante respire — en plus de faire la photosynthèse le jour.',NULL,NULL,'respiration cellulaire, photosynthèse, dioxygène',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0050','pratiques_potager',1,'Pourquoi associer le maïs, le haricot et la courge sur une même planche ?','Parce qu\'ils s\'entraident (soutien, azote, ombre au sol)','Parce qu\'ils ont la même couleur','Pour qu\'ils se gênent','Cela n\'a aucun intérêt',NULL,'A','Parce qu\'ils s\'entraident (soutien, azote, ombre au sol)','college',2,'⭐⭐ Moyen','Exact ! Le maïs sert de tuteur, le haricot enrichit le sol en azote, la courge couvre le sol : c\'est la « milpa ».','Exact ! Le maïs sert de tuteur, le haricot enrichit le sol en azote, la courge couvre le sol : c\'est la « milpa ».',NULL,NULL,'Au contraire, certaines plantes bien associées s\'entraident : c\'est tout l\'intérêt du compagnonnage.',NULL,NULL,'association de plantes, compagnonnage, milpa',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0051','pratiques_potager',2,'À quoi sert le paillage (couvrir le sol de paille ou de feuilles) ?','Garder l\'humidité et limiter les herbes indésirables','Empêcher les plantes de pousser','Attirer les pucerons','Refroidir les racines en hiver',NULL,'A','Garder l\'humidité et limiter les herbes indésirables','college',1,'⭐ Facile','Oui ! Le paillage réduit l\'évaporation, freine les herbes spontanées et nourrit le sol en se décomposant.','Oui ! Le paillage réduit l\'évaporation, freine les herbes spontanées et nourrit le sol en se décomposant.','Le paillage gêne les herbes indésirables mais laisse pousser les cultures : on paille autour d\'elles.',NULL,NULL,NULL,NULL,'paillage, sol, arrosage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0052','pratiques_potager',3,'Pourquoi changer l\'emplacement des cultures chaque année (rotation) ?','Pour ne pas épuiser le sol et limiter les maladies','Pour décorer le jardin','Cela abîme le sol','Pour que tout pousse plus lentement',NULL,'A','Pour ne pas épuiser le sol et limiter les maladies','lycee',2,'⭐⭐ Moyen','Bravo ! En ne replantant pas la même famille au même endroit, on préserve la fertilité et on casse le cycle des maladies.','Bravo ! En ne replantant pas la même famille au même endroit, on préserve la fertilité et on casse le cycle des maladies.',NULL,'C\'est l\'inverse : la rotation protège le sol et évite de l\'épuiser.',NULL,NULL,NULL,'rotation des cultures, sol, maladies',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0060','semis_recolte',1,'Qu\'est-ce qu\'une plante annuelle ?','Une plante qui accomplit tout son cycle en une seule année','Une plante qui vit plusieurs années','Une plante qui ne fleurit jamais','Une plante d\'intérieur',NULL,'A','Une plante qui accomplit tout son cycle en une seule année','college',1,'⭐ Facile','Oui ! Une annuelle germe, fleurit, fait ses graines et meurt en une saison : il faut la ressemer chaque année.','Oui ! Une annuelle germe, fleurit, fait ses graines et meurt en une saison : il faut la ressemer chaque année.','Une plante qui vit plusieurs années est une vivace, pas une annuelle.',NULL,NULL,NULL,NULL,'plante annuelle, cycle de vie, semis',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0061','semis_recolte',2,'Qu\'est-ce qu\'une bouture ?','Un morceau de plante qui forme des racines et donne une nouvelle plante','Une graine spéciale','Une maladie des plantes','Un type d\'engrais',NULL,'A','Un morceau de plante qui forme des racines et donne une nouvelle plante','college',2,'⭐⭐ Moyen','Exact ! Le bouturage multiplie une plante sans graine : on replante un fragment de tige qui s\'enracine.','Exact ! Le bouturage multiplie une plante sans graine : on replante un fragment de tige qui s\'enracine.','Une bouture n\'est pas une graine : c\'est un fragment de plante qui développe ses propres racines.',NULL,NULL,NULL,NULL,'bouture, multiplication, vivace',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0062','semis_recolte',3,'Quand récolter une salade pour qu\'elle reste tendre ?','Avant qu\'elle ne « monte » en fleur','Après la floraison','Seulement en hiver','Quand les feuilles jaunissent',NULL,'A','Avant qu\'elle ne « monte » en fleur','college',2,'⭐⭐ Moyen','Oui ! Une fois montée en fleur, la salade devient amère et dure : on la récolte avant la floraison.','Oui ! Une fois montée en fleur, la salade devient amère et dure : on la récolte avant la floraison.','Après la floraison, la salade devient amère : il faut la récolter avant qu\'elle ne monte.',NULL,NULL,NULL,NULL,'récolte, floraison, potager',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0070','ravageurs_auxiliaires',1,'Le puceron est considéré comme…','un ravageur (il pique la sève des plantes)','un auxiliaire utile','un pollinisateur','un décomposeur',NULL,'A','un ravageur (il pique la sève des plantes)','college',1,'⭐ Facile','Exact ! Le puceron prélève la sève et affaiblit les plantes : c\'est un ravageur courant du potager.','Exact ! Le puceron prélève la sève et affaiblit les plantes : c\'est un ravageur courant du potager.','Le puceron n\'aide pas le jardinier : c\'est un ravageur. Ses prédateurs, eux, sont des auxiliaires.',NULL,NULL,NULL,NULL,'puceron, ravageur, herbivorie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0071','ravageurs_auxiliaires',2,'Lequel de ces animaux est un auxiliaire (allié contre les ravageurs) ?','La mante religieuse','Le puceron','La cochenille','La piéride du chou',NULL,'A','La mante religieuse','college',2,'⭐⭐ Moyen','Oui ! La mante religieuse est un prédateur qui dévore d\'autres insectes : c\'est une alliée du jardinier.','Oui ! La mante religieuse est un prédateur qui dévore d\'autres insectes : c\'est une alliée du jardinier.','Le puceron est justement un ravageur ; l\'auxiliaire est son prédateur, comme la mante ou l\'araignée.',NULL,NULL,NULL,NULL,'auxiliaire, prédation, lutte biologique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0072','ravageurs_auxiliaires',3,'Sur quelles plantes la piéride du chou pond-elle ses œufs ?','Sur les choux et autres Brassicacées','Sur les tomates','Sur les cactus','Sur les nénuphars',NULL,'A','Sur les choux et autres Brassicacées','lycee',2,'⭐⭐ Moyen','Bravo ! Le chou est la plante-hôte des chenilles de la piéride : c\'est là qu\'elle pond pour nourrir ses larves.','Bravo ! Le chou est la plante-hôte des chenilles de la piéride : c\'est là qu\'elle pond pour nourrir ses larves.','La piéride du chou vise les Brassicacées (chou, radis, navet, roquette), pas la tomate.',NULL,NULL,NULL,NULL,'piéride, plante-hôte, ravageur',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0073','ravageurs_auxiliaires',4,'Quelle est une alternative aux pesticides chimiques contre les ravageurs ?','La lutte biologique (favoriser leurs prédateurs naturels)','Arroser davantage','Mettre plus d\'engrais','Couper toutes les fleurs',NULL,'A','La lutte biologique (favoriser leurs prédateurs naturels)','college',2,'⭐⭐ Moyen','Exact ! Accueillir araignées, mantes et coccinelles régule les ravageurs sans polluer : c\'est la lutte biologique.','Exact ! Accueillir araignées, mantes et coccinelles régule les ravageurs sans polluer : c\'est la lutte biologique.',NULL,'L\'engrais nourrit les plantes mais ne combat pas les ravageurs ; la lutte biologique, oui.',NULL,NULL,NULL,'lutte biologique, auxiliaire, pesticide',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0080','eau_arrosage',1,'À quel moment vaut-il mieux arroser pour limiter l\'évaporation ?','Le matin tôt ou le soir','En plein midi','Jamais','Seulement quand il pleut',NULL,'A','Le matin tôt ou le soir','college',1,'⭐ Facile','Oui ! Aux heures fraîches, l\'eau s\'évapore moins et profite mieux aux racines.','Oui ! Aux heures fraîches, l\'eau s\'évapore moins et profite mieux aux racines.','En plein midi, une grande partie de l\'eau s\'évapore avant d\'atteindre les racines.',NULL,NULL,NULL,NULL,'arrosage, évaporation, eau',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0081','eau_arrosage',2,'Pourquoi un bon drainage est-il important pour les plantes en pot ?','Pour éviter que les racines pourrissent dans l\'eau stagnante','Pour que la plante boive moins','Pour attirer les moustiques','Cela n\'a pas d\'importance',NULL,'A','Pour éviter que les racines pourrissent dans l\'eau stagnante','lycee',2,'⭐⭐ Moyen','Exact ! Sans drainage, l\'eau stagne et asphyxie les racines, qui pourrissent. L\'eau en excès doit pouvoir s\'écouler.','Exact ! Sans drainage, l\'eau stagne et asphyxie les racines, qui pourrissent. L\'eau en excès doit pouvoir s\'écouler.',NULL,NULL,'Au contraire, un mauvais drainage fait pourrir les racines : c\'est une cause fréquente de plantes mortes en pot.',NULL,NULL,'drainage, eau, racine',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0090','energie_matiere',1,'Pourquoi une chaîne alimentaire compte-t-elle rarement plus de 4 ou 5 maillons ?','Parce que ~90 % de l\'énergie est perdue à chaque niveau','Parce que les animaux sont trop gros','Parce qu\'il n\'y a pas assez d\'espèces','Parce que l\'énergie augmente trop vite',NULL,'A','Parce que ~90 % de l\'énergie est perdue à chaque niveau','lycee',3,'⭐⭐⭐ Difficile','Bravo ! À chaque transfert, seule ~10 % de l\'énergie passe au niveau suivant : il ne reste plus assez d\'énergie pour de longs maillons.','Bravo ! À chaque transfert, seule ~10 % de l\'énergie passe au niveau suivant : il ne reste plus assez d\'énergie pour de longs maillons.',NULL,NULL,'C\'est l\'inverse : l\'énergie diminue (et non augmente) à chaque niveau trophique.',NULL,NULL,'flux d\'énergie, rendement écologique, niveau trophique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0091','energie_matiere',2,'Qu\'appelle-t-on la production primaire d\'un écosystème ?','La matière organique fabriquée par les producteurs (photosynthèse)','La quantité de prédateurs','La masse des décomposeurs','La pluie tombée dans l\'année',NULL,'A','La matière organique fabriquée par les producteurs (photosynthèse)','lycee',2,'⭐⭐ Moyen','Exact ! La production primaire est la matière créée par les plantes ; elle constitue la base énergétique de tout l\'écosystème.','Exact ! La production primaire est la matière créée par les plantes ; elle constitue la base énergétique de tout l\'écosystème.','Les prédateurs relèvent de la production secondaire ; la production primaire, c\'est celle des producteurs.',NULL,NULL,NULL,NULL,'production primaire, producteur, biomasse',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0092','energie_matiere',3,'Dans une pyramide des biomasses, où trouve-t-on le plus de matière vivante ?','À la base, chez les producteurs','Au sommet, chez les prédateurs','Au milieu, chez les herbivores','C\'est réparti également',NULL,'A','À la base, chez les producteurs','lycee',2,'⭐⭐ Moyen','Oui ! Les producteurs forment la large base de la pyramide ; la biomasse diminue à chaque niveau supérieur.','Oui ! Les producteurs forment la large base de la pyramide ; la biomasse diminue à chaque niveau supérieur.','Au sommet, les prédateurs sont peu nombreux : c\'est à la base (producteurs) qu\'il y a le plus de biomasse.',NULL,NULL,NULL,NULL,'pyramide écologique, biomasse, niveau trophique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0093','energie_matiere',4,'Contrairement à l\'énergie, que fait la matière (carbone, azote…) dans un écosystème ?','Elle se recycle en boucle entre vivant et milieu','Elle disparaît définitivement','Elle ne bouge jamais','Elle augmente sans cesse',NULL,'A','Elle se recycle en boucle entre vivant et milieu','lycee',3,'⭐⭐⭐ Difficile','Exact ! L\'énergie circule à sens unique et se perd, mais la matière est recyclée en boucle : ce sont les cycles biogéochimiques.','Exact ! L\'énergie circule à sens unique et se perd, mais la matière est recyclée en boucle : ce sont les cycles biogéochimiques.','La matière ne disparaît pas : elle est recyclée. C\'est l\'énergie, elle, qui se perd à chaque niveau.',NULL,NULL,NULL,NULL,'cycle biogéochimique, matière, flux d\'énergie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0094','energie_matiere',5,'En quoi le compostage agit-il sur le cycle du carbone ?','Il renvoie du carbone au sol au lieu de le relâcher dans l\'air','Il fabrique du pétrole','Il supprime tout le carbone','Il n\'a aucun effet sur le carbone',NULL,'A','Il renvoie du carbone au sol au lieu de le relâcher dans l\'air','college',2,'⭐⭐ Moyen','Oui ! Composter stocke une partie du carbone dans l\'humus du sol, au lieu de le perdre en le brûlant.','Oui ! Composter stocke une partie du carbone dans l\'humus du sol, au lieu de le perdre en le brûlant.',NULL,NULL,'Le compostage agit bien sur le cycle du carbone : il en stocke une partie dans le sol.',NULL,NULL,'cycle du carbone, compostage, humus',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0100','cellule_metabolisme',1,'De quoi tous les êtres vivants sont-ils constitués ?','De cellules','De cristaux','De fibres de plastique','De minéraux uniquement',NULL,'A','De cellules','lycee',1,'⭐ Facile','Exact ! La cellule est la plus petite unité du vivant : une seule chez une bactérie, des milliards chez une plante.','Exact ! La cellule est la plus petite unité du vivant : une seule chez une bactérie, des milliards chez une plante.',NULL,NULL,'Les minéraux composent le non-vivant ; les êtres vivants, eux, sont faits de cellules.',NULL,NULL,'cellule, micro-organisme',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0101','cellule_metabolisme',2,'Dans quel élément de la cellule végétale se déroule la photosynthèse ?','Le chloroplaste','Le noyau','La mitochondrie','La paroi',NULL,'A','Le chloroplaste','lycee',3,'⭐⭐⭐ Difficile','Bravo ! Les chloroplastes contiennent la chlorophylle et captent la lumière pour fabriquer les sucres.','Bravo ! Les chloroplastes contiennent la chlorophylle et captent la lumière pour fabriquer les sucres.',NULL,'La mitochondrie est le siège de la respiration ; la photosynthèse, elle, se fait dans le chloroplaste.',NULL,NULL,NULL,'chloroplaste, photosynthèse, chlorophylle',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0102','cellule_metabolisme',3,'La respiration cellulaire consomme du dioxygène et produit…','du dioxyde de carbone et de l\'énergie (ATP)','de la lumière','de l\'ammonium','des protéines',NULL,'A','du dioxyde de carbone et de l\'énergie (ATP)','lycee',3,'⭐⭐⭐ Difficile','Exact ! En dégradant les sucres avec de l\'O2, la cellule libère de l\'énergie (ATP) et rejette du CO2 et de l\'eau.','Exact ! En dégradant les sucres avec de l\'O2, la cellule libère de l\'énergie (ATP) et rejette du CO2 et de l\'eau.','La respiration ne produit pas de lumière : elle libère de l\'énergie chimique (ATP) utilisable par la cellule.',NULL,NULL,NULL,NULL,'respiration cellulaire, ATP, dioxygène',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0103','cellule_metabolisme',4,'Qu\'est-ce que l\'ATP ?','La molécule qui fournit l\'énergie aux cellules','Un type de sucre du sol','Une bactérie','Une vitamine des feuilles',NULL,'A','La molécule qui fournit l\'énergie aux cellules','lycee',3,'⭐⭐⭐ Difficile','Oui ! L\'ATP est la « monnaie énergétique » de la cellule, produite par la respiration et utilisée par toutes ses activités.','Oui ! L\'ATP est la « monnaie énergétique » de la cellule, produite par la respiration et utilisée par toutes ses activités.',NULL,'L\'ATP n\'est pas un être vivant : c\'est une molécule qui transporte l\'énergie dans la cellule.',NULL,NULL,NULL,'ATP, respiration cellulaire, cellule',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0104','cellule_metabolisme',5,'Quand a lieu la fermentation (ex. dans un compost trop tassé) ?','En l\'absence d\'oxygène','En plein soleil','Seulement à 0 °C','Uniquement avec beaucoup d\'air',NULL,'A','En l\'absence d\'oxygène','lycee',2,'⭐⭐ Moyen','Exact ! Privés d\'oxygène, des micro-organismes dégradent la matière par fermentation, ce qui dégage de mauvaises odeurs.','Exact ! Privés d\'oxygène, des micro-organismes dégradent la matière par fermentation, ce qui dégage de mauvaises odeurs.',NULL,NULL,'Avec beaucoup d\'air, c\'est la décomposition aérobie qui domine ; la fermentation, elle, se fait sans oxygène.',NULL,NULL,'fermentation, oxygène, compost',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0110','evolution_biodiversite',1,'Quel mécanisme, décrit par Darwin, est le moteur de l\'évolution ?','La sélection naturelle','La photosynthèse','La nitrification','Le hasard pur sans aucune règle',NULL,'A','La sélection naturelle','lycee',2,'⭐⭐ Moyen','Bravo ! Les individus les mieux adaptés survivent et se reproduisent davantage : leurs caractères se répandent.','Bravo ! Les individus les mieux adaptés survivent et se reproduisent davantage : leurs caractères se répandent.',NULL,NULL,'Il y a du hasard dans les variations, mais c\'est la sélection naturelle (un tri) qui oriente l\'évolution.',NULL,NULL,'sélection naturelle, évolution, adaptation',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0111','evolution_biodiversite',2,'Chou, brocoli et chou-fleur proviennent…','d\'une même espèce sauvage sélectionnée par l\'humain','de trois espèces sans aucun lien','de croisements avec des animaux','d\'une plante des océans',NULL,'A','d\'une même espèce sauvage sélectionnée par l\'humain','lycee',3,'⭐⭐⭐ Difficile','Exact ! Ce sont des formes domestiquées d\'une même espèce (Brassica oleracea) : un bel exemple de domestication.','Exact ! Ce sont des formes domestiquées d\'une même espèce (Brassica oleracea) : un bel exemple de domestication.','Au contraire, ils descendent tous de la même espèce sauvage, façonnée par la sélection humaine.',NULL,NULL,NULL,NULL,'domestication, évolution, espèce',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0112','evolution_biodiversite',3,'Pourquoi conserver et ressemer des variétés anciennes (semences paysannes) ?','Pour préserver la diversité génétique et l\'adaptabilité','Pour réduire les récoltes','Parce que c\'est interdit autrement','Cela n\'a aucun intérêt',NULL,'A','Pour préserver la diversité génétique et l\'adaptabilité','lycee',2,'⭐⭐ Moyen','Oui ! Une grande diversité génétique rend les cultures plus résistantes aux maladies et au changement climatique.','Oui ! Une grande diversité génétique rend les cultures plus résistantes aux maladies et au changement climatique.',NULL,NULL,'Au contraire, la diversité génétique est un atout majeur pour l\'avenir des cultures.',NULL,NULL,'diversité génétique, semence, biodiversité',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0113','evolution_biodiversite',4,'La gambusie, petit poisson introduit pour manger les larves de moustiques, est aujourd\'hui considérée comme…','une espèce invasive dans de nombreuses régions','une espèce protégée','une plante aquatique','un décomposeur',NULL,'A','une espèce invasive dans de nombreuses régions','lycee',3,'⭐⭐⭐ Difficile','Exact ! Introduite hors de son aire d\'origine, elle prolifère et menace la faune locale : une introduction « utile » qui a mal tourné.','Exact ! Introduite hors de son aire d\'origine, elle prolifère et menace la faune locale : une introduction « utile » qui a mal tourné.','C\'est le contraire d\'une espèce à protéger : la gambusie est devenue invasive et menace la biodiversité locale.',NULL,NULL,NULL,NULL,'espèce invasive, biodiversité, gambusie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0114','evolution_biodiversite',5,'La biodiversité se mesure à trois niveaux. Lesquels ?','Les gènes, les espèces et les écosystèmes','Le sol, l\'eau et l\'air','Les plantes, les pierres et l\'eau','Le passé, le présent et le futur',NULL,'A','Les gènes, les espèces et les écosystèmes','college',2,'⭐⭐ Moyen','Bravo ! La biodiversité, c\'est la diversité génétique, la diversité des espèces et la diversité des milieux.','Bravo ! La biodiversité, c\'est la diversité génétique, la diversité des espèces et la diversité des milieux.','Sol, eau et air sont des facteurs du milieu (abiotiques), pas les niveaux de la biodiversité.',NULL,NULL,NULL,NULL,'biodiversité, diversité génétique, espèce',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0115','evolution_biodiversite',6,'Comment s\'écrit le nom scientifique d\'une espèce ?','En deux mots latins : le genre puis l\'espèce','En un seul mot français','Avec un chiffre','Toujours en majuscules',NULL,'A','En deux mots latins : le genre puis l\'espèce','college',2,'⭐⭐ Moyen','Exact ! Exemple : Solanum lycopersicum pour la tomate. Ce nom est compris partout dans le monde.','Exact ! Exemple : Solanum lycopersicum pour la tomate. Ce nom est compris partout dans le monde.','Le nom commun varie d\'un pays à l\'autre ; le nom scientifique, lui, est en deux mots latins universels.',NULL,NULL,NULL,NULL,'nom scientifique, taxonomie, genre, espèce',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0120','populations_equilibres',1,'Que se passe-t-il pour une population de pucerons s\'il n\'y a aucun prédateur ?','Elle peut exploser (pullulation)','Elle disparaît aussitôt','Elle reste exactement stable','Elle se transforme en plante',NULL,'A','Elle peut exploser (pullulation)','lycee',2,'⭐⭐ Moyen','Exact ! Sans régulation par les prédateurs, la population croît très vite : d\'où l\'intérêt de favoriser les auxiliaires.','Exact ! Sans régulation par les prédateurs, la population croît très vite : d\'où l\'intérêt de favoriser les auxiliaires.',NULL,'Sans prédateurs ni manque de ressources, rien ne freine la population : elle a tendance à exploser.',NULL,NULL,NULL,'dynamique des populations, prédation, ravageur',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0121','populations_equilibres',2,'Qu\'est-ce qu\'un « facteur limitant » ?','La ressource la plus rare qui freine la croissance','La plus grande quantité disponible','Un animal nuisible','Un outil de jardin',NULL,'A','La ressource la plus rare qui freine la croissance','lycee',3,'⭐⭐⭐ Difficile','Bravo ! La croissance est bornée par l\'élément le plus rare : lumière, eau, azote… L\'identifier permet d\'agir efficacement.','Bravo ! La croissance est bornée par l\'élément le plus rare : lumière, eau, azote… L\'identifier permet d\'agir efficacement.','C\'est l\'inverse : le facteur limitant est la ressource qui manque, pas celle qui abonde.',NULL,NULL,NULL,NULL,'facteur limitant, ressource',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0122','populations_equilibres',3,'Que désigne la « capacité de charge » d\'un milieu ?','Le nombre maximal d\'individus qu\'il peut nourrir durablement','Le poids qu\'un sol peut supporter','Le nombre d\'espèces différentes','La quantité de pluie',NULL,'A','Le nombre maximal d\'individus qu\'il peut nourrir durablement','lycee',3,'⭐⭐⭐ Difficile','Exact ! Au-delà de cette limite fixée par les ressources, la population ne peut plus croître. Un bac d\'aquaponie a sa capacité de charge en poissons.','Exact ! Au-delà de cette limite fixée par les ressources, la population ne peut plus croître. Un bac d\'aquaponie a sa capacité de charge en poissons.','Il ne s\'agit pas d\'un poids physique, mais du nombre d\'individus que les ressources du milieu peuvent nourrir.',NULL,NULL,NULL,NULL,'capacité de charge, dynamique des populations',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0123','populations_equilibres',4,'Pourquoi un écosystème (ou un jardin) très diversifié est-il plus solide ?','Il est plus résilient face aux perturbations','Il est plus fragile','Il pousse plus lentement','Il attire plus de maladies',NULL,'A','Il est plus résilient face aux perturbations','lycee',2,'⭐⭐ Moyen','Oui ! La diversité offre des relais : si une espèce flanche, d\'autres compensent. La biodiversité renforce la résilience.','Oui ! La diversité offre des relais : si une espèce flanche, d\'autres compensent. La biodiversité renforce la résilience.','C\'est le contraire : la diversité rend l\'écosystème plus solide, pas plus fragile.',NULL,NULL,NULL,NULL,'résilience, biodiversité, équilibre',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0124','populations_equilibres',5,'Une parcelle abandonnée se couvre d\'herbes, puis d\'arbustes, puis d\'arbres. Comment nomme-t-on cette évolution ?','Une succession écologique','Une rotation des cultures','Une pollinisation','Une fermentation',NULL,'A','Une succession écologique','lycee',3,'⭐⭐⭐ Difficile','Bravo ! La communauté se transforme progressivement vers un état plus stable : c\'est une succession écologique.','Bravo ! La communauté se transforme progressivement vers un état plus stable : c\'est une succession écologique.','La rotation est une pratique agricole volontaire ; ici, le milieu évolue naturellement : c\'est une succession.',NULL,NULL,NULL,NULL,'succession écologique, résilience',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0125','populations_equilibres',6,'La température d\'un milieu est un facteur…','abiotique (non vivant)','biotique (vivant)','trophique','génétique',NULL,'A','abiotique (non vivant)','lycee',2,'⭐⭐ Moyen','Exact ! La température, la lumière, l\'eau et le pH sont des facteurs abiotiques : ils décrivent les conditions physiques du milieu.','Exact ! La température, la lumière, l\'eau et le pH sont des facteurs abiotiques : ils décrivent les conditions physiques du milieu.','Un facteur biotique vient des êtres vivants (prédation, compétition) ; la température, elle, est abiotique.',NULL,NULL,NULL,NULL,'facteur abiotique, facteur biotique, pH',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0130','agroecologie_permaculture',1,'De quoi s\'inspire la permaculture pour concevoir des jardins ?','Du fonctionnement des écosystèmes naturels','Des usines','Des jeux vidéo','Du hasard',NULL,'A','Du fonctionnement des écosystèmes naturels','college',2,'⭐⭐ Moyen','Exact ! La permaculture imite la nature : étager les plantes, recycler, coopérer avec le milieu plutôt que lutter contre lui.','Exact ! La permaculture imite la nature : étager les plantes, recycler, coopérer avec le milieu plutôt que lutter contre lui.','La permaculture s\'inspire des écosystèmes, pas des usines : elle vise l\'autonomie et la durabilité.',NULL,NULL,NULL,NULL,'permaculture, agroécologie, forêt comestible',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0131','agroecologie_permaculture',2,'Qu\'est-ce qu\'une forêt comestible (jardin-forêt) ?','Un jardin à plusieurs étages de plantes utiles, comme une forêt','Une forêt qu\'on coupe pour cultiver','Un potager sans aucune plante vivace','Une forêt interdite d\'accès',NULL,'A','Un jardin à plusieurs étages de plantes utiles, comme une forêt','college',2,'⭐⭐ Moyen','Oui ! Arbres fruitiers, arbustes, herbacées et couvre-sols se superposent en strates productives et autonomes.','Oui ! Arbres fruitiers, arbustes, herbacées et couvre-sols se superposent en strates productives et autonomes.','On ne coupe pas la forêt : on imite sa structure en étages pour produire durablement.',NULL,NULL,NULL,NULL,'forêt comestible, permaculture, strates',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0132','agroecologie_permaculture',3,'Pourquoi les légumineuses (haricot, fève, pois) enrichissent-elles le sol en azote ?','Grâce à des bactéries fixatrices d\'azote dans leurs racines','Parce qu\'elles ont de grandes feuilles','Parce qu\'elles poussent vite','Parce qu\'on les arrose plus',NULL,'A','Grâce à des bactéries fixatrices d\'azote dans leurs racines','lycee',3,'⭐⭐⭐ Difficile','Exact ! Les bactéries des nodosités fixent l\'azote de l\'air et le partagent avec la plante : le sol s\'enrichit naturellement.','Exact ! Les bactéries des nodosités fixent l\'azote de l\'air et le partagent avec la plante : le sol s\'enrichit naturellement.','Ce n\'est pas une question de feuilles : c\'est la symbiose racinaire avec des bactéries fixatrices d\'azote.',NULL,NULL,NULL,NULL,'fixation de l\'azote, nodosité, symbiose, légumineuse',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0133','agroecologie_permaculture',4,'Qu\'est-ce que la lutte biologique ?','Contrôler les ravageurs grâce à leurs ennemis naturels','Pulvériser plus de pesticides','Arracher toutes les plantes','Brûler les déchets',NULL,'A','Contrôler les ravageurs grâce à leurs ennemis naturels','college',2,'⭐⭐ Moyen','Bravo ! Accueillir prédateurs et parasites des ravageurs permet de s\'en passer de produits chimiques.','Bravo ! Accueillir prédateurs et parasites des ravageurs permet de s\'en passer de produits chimiques.','La lutte biologique est justement une alternative aux pesticides, pas leur renforcement.',NULL,NULL,NULL,NULL,'lutte biologique, auxiliaire, pesticide',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0134','agroecologie_permaculture',5,'Qu\'est-ce que l\'allélopathie entre plantes ?','L\'influence chimique d\'une plante sur la croissance de ses voisines','Le fait de se toucher physiquement','Une maladie contagieuse','Un type d\'arrosage',NULL,'A','L\'influence chimique d\'une plante sur la croissance de ses voisines','lycee',3,'⭐⭐⭐ Difficile','Exact ! Certaines plantes libèrent des substances qui freinent (ou favorisent) leurs voisines : on en tient compte dans les associations.','Exact ! Certaines plantes libèrent des substances qui freinent (ou favorisent) leurs voisines : on en tient compte dans les associations.','Il ne s\'agit pas de contact physique mais d\'un effet chimique à distance, via des substances libérées.',NULL,NULL,NULL,NULL,'allélopathie, association de plantes, interaction',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0140','environnement_durable',1,'Qu\'est-ce qui provoque l\'eutrophisation d\'une eau (mare, rivière) ?','Un excès de nutriments (nitrates, phosphates)','Un manque total de vie','Trop de cailloux','Une eau trop froide',NULL,'A','Un excès de nutriments (nitrates, phosphates)','lycee',3,'⭐⭐⭐ Difficile','Exact ! L\'excès de nutriments fait proliférer les algues ; en se décomposant, elles consomment l\'oxygène et asphyxient le milieu.','Exact ! L\'excès de nutriments fait proliférer les algues ; en se décomposant, elles consomment l\'oxygène et asphyxient le milieu.','Au contraire, l\'eutrophisation vient d\'un trop-plein de nutriments, pas d\'un manque de vie.',NULL,NULL,NULL,NULL,'eutrophisation, nitrate, pollution',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0141','environnement_durable',2,'Que devient une grande partie des nitrates quand la pluie traverse un sol nu ?','Ils sont lessivés et polluent les nappes d\'eau','Ils montent dans l\'air','Ils deviennent des cailloux','Ils disparaissent sans effet',NULL,'A','Ils sont lessivés et polluent les nappes d\'eau','lycee',3,'⭐⭐⭐ Difficile','Exact ! Le lessivage entraîne les nitrates en profondeur : perte de fertilité pour le sol et pollution des nappes.','Exact ! Le lessivage entraîne les nitrates en profondeur : perte de fertilité pour le sol et pollution des nappes.',NULL,NULL,'Les nitrates lessivés ne disparaissent pas : ils polluent les eaux souterraines.',NULL,NULL,'lessivage, nitrate, pollution, sol',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0142','environnement_durable',3,'Pourquoi un usage excessif de pesticides pose-t-il problème au jardin ?','Il tue aussi les auxiliaires utiles, comme les abeilles','Il fait pousser les plantes trop vite','Il améliore la biodiversité','Il n\'a aucun effet secondaire',NULL,'A','Il tue aussi les auxiliaires utiles, comme les abeilles','college',2,'⭐⭐ Moyen','Exact ! Les pesticides ne font pas le tri : ils touchent pollinisateurs et prédateurs de ravageurs, et polluent le milieu.','Exact ! Les pesticides ne font pas le tri : ils touchent pollinisateurs et prédateurs de ravageurs, et polluent le milieu.',NULL,'Au contraire, les pesticides réduisent la biodiversité en touchant aussi les espèces utiles.',NULL,NULL,NULL,'pesticide, auxiliaire, pollution, lutte biologique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0143','environnement_durable',4,'Que cherche le « développement durable » ?','Répondre à nos besoins sans compromettre ceux des générations futures','Produire le plus possible tout de suite','Abandonner toute agriculture','Utiliser uniquement des machines',NULL,'A','Répondre à nos besoins sans compromettre ceux des générations futures','college',2,'⭐⭐ Moyen','Bravo ! Il cherche l\'équilibre entre besoins humains, respect de la nature et avenir de la planète.','Bravo ! Il cherche l\'équilibre entre besoins humains, respect de la nature et avenir de la planète.','Produire à tout prix aujourd\'hui, c\'est justement le contraire du développement durable.',NULL,NULL,NULL,NULL,'développement durable, ressource naturelle, agroécologie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0144','environnement_durable',5,'Composter ses déchets de cuisine et de jardin permet de…','recycler la matière et nourrir le sol','fabriquer du plastique','produire de l\'électricité directement','supprimer la vie du sol',NULL,'A','recycler la matière et nourrir le sol','college',1,'⭐ Facile','Exact ! Le compostage transforme les déchets organiques en engrais naturel : on réduit les déchets et on enrichit le sol.','Exact ! Le compostage transforme les déchets organiques en engrais naturel : on réduit les déchets et on enrichit le sol.',NULL,NULL,'Au contraire, le compost nourrit et stimule la vie du sol.',NULL,NULL,'compostage, recyclage, déchet organique, humus',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0200','vivant_classification',5,'À quel grand groupe appartient le cloporte ?','Aux crustacés (un arthropode)','Aux insectes','Aux vers','Aux mollusques',NULL,'A','Aux crustacés (un arthropode)','lycee',3,'⭐⭐⭐ Difficile','Surprenant mais vrai : le cloporte est un crustacé terrestre, cousin des crevettes, et donc un arthropode.','Surprenant mais vrai : le cloporte est un crustacé terrestre, cousin des crevettes, et donc un arthropode.','Le cloporte a plus de six pattes et une carapace de crustacé : ce n\'est pas un insecte.',NULL,NULL,NULL,NULL,'cloporte, crustacé, arthropode, classification',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0201','vivant_classification',6,'L\'escargot et la limnée appartiennent au groupe des…','mollusques','insectes','vers','crustacés',NULL,'A','mollusques','college',2,'⭐⭐ Moyen','Exact ! Corps mou, souvent une coquille : ce sont des mollusques (gastéropodes).','Exact ! Corps mou, souvent une coquille : ce sont des mollusques (gastéropodes).',NULL,'Un ver n\'a pas de coquille ; l\'escargot, au corps mou avec coquille, est un mollusque.',NULL,NULL,NULL,'mollusque, gastéropode, classification',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0202','vivant_classification',7,'Le champignon est…','ni une plante ni un animal (un règne à part)','une plante sans chlorophylle','un petit animal','une bactérie',NULL,'A','ni une plante ni un animal (un règne à part)','lycee',2,'⭐⭐ Moyen','Exact ! Les champignons forment leur propre règne ; ils se nourrissent de matière organique, sans photosynthèse.','Exact ! Les champignons forment leur propre règne ; ils se nourrissent de matière organique, sans photosynthèse.','Le champignon n\'est pas une plante : il ne fait pas de photosynthèse et forme un règne distinct.',NULL,NULL,NULL,NULL,'champignon, classification, règne',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0203','vivant_classification',8,'Qu\'est-ce qui caractérise un vertébré ?','Il possède une colonne vertébrale (squelette interne)','Il a une carapace','Il n\'a pas de cœur','Il a toujours huit pattes',NULL,'A','Il possède une colonne vertébrale (squelette interne)','college',2,'⭐⭐ Moyen','Oui ! Poissons, oiseaux, mammifères… ont un squelette interne avec une colonne vertébrale.','Oui ! Poissons, oiseaux, mammifères… ont un squelette interne avec une colonne vertébrale.','Une carapace est le propre des arthropodes (invertébrés) ; le vertébré a un squelette interne.',NULL,NULL,NULL,NULL,'vertébré, invertébré, classification',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0210','ecologie_reseaux',6,'Un animal qui mange à la fois des plantes et des animaux est…','un omnivore','un herbivore strict','un producteur','un décomposeur',NULL,'A','un omnivore','college',1,'⭐ Facile','Exact ! L\'omnivore a un régime mixte ; beaucoup de poissons, et l\'humain, sont omnivores.','Exact ! L\'omnivore a un régime mixte ; beaucoup de poissons, et l\'humain, sont omnivores.','L\'herbivore ne mange que des plantes ; l\'omnivore, lui, mange des deux.',NULL,NULL,NULL,NULL,'omnivore, régime alimentaire, consommateur',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0211','ecologie_reseaux',7,'Pourquoi dit-on que les plantes sont indispensables à tout l\'écosystème ?','Elles produisent la matière et l\'oxygène dont dépendent les autres','Parce qu\'elles sont jolies','Parce qu\'elles mangent les animaux','Elles ne sont pas indispensables',NULL,'A','Elles produisent la matière et l\'oxygène dont dépendent les autres','college',2,'⭐⭐ Moyen','Exact ! Productrices par photosynthèse, elles nourrissent toute la chaîne et renouvellent l\'oxygène.','Exact ! Productrices par photosynthèse, elles nourrissent toute la chaîne et renouvellent l\'oxygène.',NULL,NULL,'Au contraire : sans producteurs, aucune chaîne alimentaire ne pourrait exister.',NULL,NULL,'producteur, photosynthèse, chaîne alimentaire',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0212','ecologie_reseaux',8,'Parmi ces êtres vivants, lequel est un décomposeur ?','Le cloporte','L\'abeille','La tomate','Le tilapia',NULL,'A','Le cloporte','college',1,'⭐ Facile','Oui ! Le cloporte fragmente la matière morte : c\'est un détritivore qui participe à la décomposition.','Oui ! Le cloporte fragmente la matière morte : c\'est un détritivore qui participe à la décomposition.','L\'abeille est un pollinisateur, pas un décomposeur.',NULL,NULL,NULL,NULL,'décomposeur, détritivore, recyclage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0220','cycle_azote_aquaponie',7,'Pourquoi faut-il « faire tourner » un bac d\'aquaponie quelques semaines avant d\'y mettre beaucoup de poissons ?','Pour laisser les bactéries nitrifiantes s\'installer','Pour réchauffer l\'eau','Pour faire pousser des algues','Ce n\'est pas nécessaire',NULL,'A','Pour laisser les bactéries nitrifiantes s\'installer','lycee',3,'⭐⭐⭐ Difficile','Exact ! Sans colonie de bactéries mature, l\'ammonium s\'accumule et devient toxique : on laisse le biofiltre « mûrir ».','Exact ! Sans colonie de bactéries mature, l\'ammonium s\'accumule et devient toxique : on laisse le biofiltre « mûrir ».',NULL,NULL,'C\'est important : sans bactéries installées, l\'eau devient vite toxique pour les poissons.',NULL,NULL,'aquaponie, biofiltre, nitrification, bactérie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0221','cycle_azote_aquaponie',8,'Que risque-t-il d\'arriver si l\'on met trop de poissons d\'un coup dans un bassin ?','L\'ammonium s\'accumule et empoisonne l\'eau','Les poissons grandissent plus vite','L\'eau devient plus claire','Rien du tout',NULL,'A','L\'ammonium s\'accumule et empoisonne l\'eau','lycee',2,'⭐⭐ Moyen','Exact ! Trop de déjections d\'un coup dépassent la capacité des bactéries : l\'ammonium toxique s\'accumule.','Exact ! Trop de déjections d\'un coup dépassent la capacité des bactéries : l\'ammonium toxique s\'accumule.',NULL,NULL,'Au contraire, c\'est risqué : les bactéries ne suivent pas et l\'eau devient toxique.',NULL,NULL,'ammonium, capacité de charge, aquaponie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0222','cycle_azote_aquaponie',9,'À quoi sert le biofiltre dans un système d\'aquaponie ?','Il offre un support où vivent les bactéries qui épurent l\'eau','Il chauffe l\'eau','Il nourrit les poissons','Il colore l\'eau',NULL,'A','Il offre un support où vivent les bactéries qui épurent l\'eau','lycee',2,'⭐⭐ Moyen','Exact ! Le biofiltre est le « rein » du système : sa grande surface héberge les bactéries nitrifiantes.','Exact ! Le biofiltre est le « rein » du système : sa grande surface héberge les bactéries nitrifiantes.',NULL,'Le biofiltre ne nourrit pas les poissons : il héberge les bactéries qui transforment leurs déchets.',NULL,NULL,NULL,'biofiltre, nitrification, aquaponie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0230','sol_compost',7,'Pour un bon compost, que faut-il équilibrer ?','Les déchets verts (azote) et les déchets bruns (carbone)','Le sucre et le sel','L\'eau chaude et l\'eau froide','Rien, tout se vaut',NULL,'A','Les déchets verts (azote) et les déchets bruns (carbone)','college',2,'⭐⭐ Moyen','Exact ! Épluchures/tontes (verts, azote) + feuilles/carton (bruns, carbone) : l\'équilibre nourrit bien les décomposeurs.','Exact ! Épluchures/tontes (verts, azote) + feuilles/carton (bruns, carbone) : l\'équilibre nourrit bien les décomposeurs.',NULL,NULL,'L\'équilibre vert/brun est essentiel : trop de verts détrempe, trop de bruns ralentit tout.',NULL,NULL,'compostage, matière organique, déchet organique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0231','sol_compost',8,'Quel rôle jouent les champignons microscopiques du sol ?','Ils décomposent la matière et aident les racines à se nourrir','Ils mangent les plantes vivantes','Ils font la photosynthèse','Ils n\'ont aucun rôle',NULL,'A','Ils décomposent la matière et aident les racines à se nourrir','lycee',3,'⭐⭐⭐ Difficile','Exact ! Décomposeurs et partenaires des racines (mycorhizes), les champignons sont des acteurs clés du sol vivant.','Exact ! Décomposeurs et partenaires des racines (mycorhizes), les champignons sont des acteurs clés du sol vivant.',NULL,'Les champignons ne font pas de photosynthèse : ils décomposent la matière et nourrissent le sol.',NULL,NULL,NULL,'champignon, décomposeur, mycorhize, sol vivant',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0232','sol_compost',9,'Que sont les détritivores comme le ver de terre et le cloporte ?','Des animaux qui se nourrissent de débris organiques','Des prédateurs de pucerons','Des plantes du sol','Des bactéries',NULL,'A','Des animaux qui se nourrissent de débris organiques','college',2,'⭐⭐ Moyen','Exact ! Ils fragmentent la matière morte et la rendent accessible aux bactéries : premiers maillons du recyclage.','Exact ! Ils fragmentent la matière morte et la rendent accessible aux bactéries : premiers maillons du recyclage.','Ce ne sont pas des prédateurs : ils mangent des débris morts, pas des proies vivantes.',NULL,NULL,NULL,NULL,'détritivore, décomposition, sol vivant',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0240','plantes_biologie',6,'À quoi servent principalement les racines d\'une plante ?','Fixer la plante et absorber l\'eau et les minéraux','Faire la photosynthèse','Attirer les abeilles','Produire le pollen',NULL,'A','Fixer la plante et absorber l\'eau et les minéraux','college',1,'⭐ Facile','Exact ! Les racines ancrent la plante et puisent eau et sels minéraux dans le sol.','Exact ! Les racines ancrent la plante et puisent eau et sels minéraux dans le sol.','La photosynthèse se fait dans les feuilles ; les racines, elles, absorbent eau et minéraux.',NULL,NULL,NULL,NULL,'racine, sels minéraux, eau',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0241','plantes_biologie',7,'À quoi sert la fleur d\'une plante ?','À la reproduction (elle donne un fruit après pollinisation)','À respirer uniquement','À absorber l\'eau','À rien de précis',NULL,'A','À la reproduction (elle donne un fruit après pollinisation)','college',2,'⭐⭐ Moyen','Exact ! La fleur attire les pollinisateurs puis, fécondée, se transforme en fruit contenant les graines.','Exact ! La fleur attire les pollinisateurs puis, fécondée, se transforme en fruit contenant les graines.',NULL,'L\'absorption d\'eau est le rôle des racines ; la fleur, elle, sert à la reproduction.',NULL,NULL,NULL,'fleur, pollinisation, fruit, reproduction',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0242','plantes_biologie',8,'Où le pollen doit-il arriver pour qu\'un fruit se forme ?','Sur le pistil (organe femelle de la fleur)','Sur les racines','Sur les feuilles','Dans le sol',NULL,'A','Sur le pistil (organe femelle de la fleur)','lycee',3,'⭐⭐⭐ Difficile','Exact ! Le pollen des étamines doit atteindre le pistil : c\'est la fécondation, qui permet la formation des graines.','Exact ! Le pollen des étamines doit atteindre le pistil : c\'est la fécondation, qui permet la formation des graines.',NULL,'Le pollen n\'agit pas sur les feuilles : il doit atteindre le pistil de la fleur.',NULL,NULL,NULL,'pollen, pistil, étamine, fleur',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0250','pratiques_potager',4,'Pourquoi vaut-il mieux ne jamais laisser un sol nu au jardin ?','Un sol couvert est protégé de l\'érosion et garde sa vie','Un sol nu pousse mieux','Pour économiser le paillis','Cela n\'a pas d\'importance',NULL,'A','Un sol couvert est protégé de l\'érosion et garde sa vie','college',2,'⭐⭐ Moyen','Exact ! Couvrir le sol (paillage, plantes) le protège de la pluie battante, du dessèchement et nourrit sa vie.','Exact ! Couvrir le sol (paillage, plantes) le protège de la pluie battante, du dessèchement et nourrit sa vie.','Un sol nu s\'érode et se dessèche : mieux vaut toujours le couvrir.',NULL,NULL,NULL,NULL,'paillage, érosion, sol vivant',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0251','pratiques_potager',5,'Pourquoi associe-t-on souvent la tomate et le basilic ?','Le basilic est réputé éloigner certains ravageurs de la tomate','Ils ont besoin l\'un de l\'autre pour fleurir','Le basilic donne de l\'eau à la tomate','Pour la couleur',NULL,'A','Le basilic est réputé éloigner certains ravageurs de la tomate','college',2,'⭐⭐ Moyen','Exact ! C\'est un compagnonnage classique : le basilic aromatique aiderait à protéger la tomate.','Exact ! C\'est un compagnonnage classique : le basilic aromatique aiderait à protéger la tomate.','Chaque plante fleurit seule ; on les associe pour l\'entraide, pas par nécessité de floraison.',NULL,NULL,NULL,NULL,'association de plantes, compagnonnage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0252','pratiques_potager',6,'Comment accueillir des auxiliaires (alliés) au jardin ?','En offrant des abris et des fleurs, sans pesticides','En bétonnant le sol','En supprimant toutes les fleurs','En traitant tout aux pesticides',NULL,'A','En offrant des abris et des fleurs, sans pesticides','college',2,'⭐⭐ Moyen','Exact ! Fleurs, haies, tas de bois et zéro pesticide attirent abeilles, araignées et autres alliés.','Exact ! Fleurs, haies, tas de bois et zéro pesticide attirent abeilles, araignées et autres alliés.',NULL,NULL,'Les pesticides tuent justement les auxiliaires : c\'est contre-productif.',NULL,NULL,'auxiliaire, biodiversité, lutte biologique, pesticide',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0253','pratiques_potager',7,'En rotation des cultures, après une plante « gourmande » en azote, il est malin de semer…','une légumineuse (haricot, fève) qui enrichit le sol','la même plante au même endroit','rien pendant trois ans','du gravier',NULL,'A','une légumineuse (haricot, fève) qui enrichit le sol','lycee',2,'⭐⭐ Moyen','Exact ! Les légumineuses fixent l\'azote et reconstituent le sol pour la culture suivante.','Exact ! Les légumineuses fixent l\'azote et reconstituent le sol pour la culture suivante.','Replanter la même chose épuise le sol et favorise les maladies : c\'est ce que la rotation évite.',NULL,NULL,NULL,NULL,'rotation des cultures, fixation de l\'azote, légumineuse',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0254','pratiques_potager',8,'Le « jardin punk » ou l\'enherbement maîtrisé consiste à…','laisser un peu de spontané pour favoriser la biodiversité','tout arracher chaque semaine','couler du béton','ne jamais récolter',NULL,'A','laisser un peu de spontané pour favoriser la biodiversité','college',2,'⭐⭐ Moyen','Exact ! Laisser des coins « sauvages » offre gîte et nourriture aux auxiliaires et pollinisateurs.','Exact ! Laisser des coins « sauvages » offre gîte et nourriture aux auxiliaires et pollinisateurs.','Tout arracher appauvrit la biodiversité ; un peu de spontané est bénéfique.',NULL,NULL,NULL,NULL,'biodiversité, auxiliaire, agroécologie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0255','pratiques_potager',9,'Pourquoi pailler permet-il d\'arroser moins souvent ?','Le paillage limite l\'évaporation de l\'eau du sol','Il empêche la pluie d\'arriver','Il rend l\'eau inutile','Il assèche le sol',NULL,'A','Le paillage limite l\'évaporation de l\'eau du sol','college',1,'⭐ Facile','Exact ! En couvrant le sol, le paillage garde l\'humidité et réduit les arrosages.','Exact ! En couvrant le sol, le paillage garde l\'humidité et réduit les arrosages.',NULL,NULL,'C\'est l\'inverse : le paillage garde le sol humide, il ne l\'assèche pas.',NULL,NULL,'paillage, arrosage, eau',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0260','semis_recolte',4,'À quelle profondeur sème-t-on en général une graine ?','Environ deux à trois fois sa taille','Le plus profond possible','À 30 cm de profondeur','Toujours posée sur le sol',NULL,'A','Environ deux à trois fois sa taille','college',2,'⭐⭐ Moyen','Exact ! Trop profond, la graine s\'épuise avant de sortir ; la règle des 2-3 fois sa taille marche bien.','Exact ! Trop profond, la graine s\'épuise avant de sortir ; la règle des 2-3 fois sa taille marche bien.','Trop profond, la jeune pousse n\'atteint pas la lumière et meurt.',NULL,NULL,NULL,NULL,'semis, semence, germination',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0261','semis_recolte',5,'Pourquoi « éclaircir » un semis trop dense ?','Pour éviter que les plants se concurrencent et donner de la place','Pour gaspiller des graines','Pour attirer les pucerons','Cela ne sert à rien',NULL,'A','Pour éviter que les plants se concurrencent et donner de la place','lycee',2,'⭐⭐ Moyen','Exact ! Trop serrés, les plants se font de l\'ombre et se disputent eau et minéraux : on en retire quelques-uns.','Exact ! Trop serrés, les plants se font de l\'ombre et se disputent eau et minéraux : on en retire quelques-uns.',NULL,NULL,'Sans éclaircir, les plants entrent en compétition et restent chétifs.',NULL,NULL,'semis, compétition, repiquage',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0262','semis_recolte',6,'Quel légume se ressème-t-il facilement d\'une année sur l\'autre en gardant ses graines ?','La tomate','Le bananier','Le champignon','Le cactus géant',NULL,'A','La tomate','college',1,'⭐ Facile','Exact ! On récolte les graines d\'une belle tomate pour les ressemer : cela préserve aussi la diversité.','Exact ! On récolte les graines d\'une belle tomate pour les ressemer : cela préserve aussi la diversité.',NULL,'Le champignon ne fait pas de graines ; la tomate, si, et elles se conservent facilement.',NULL,NULL,NULL,'semence, diversité génétique, récolte',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0263','semis_recolte',7,'Quelle plante se multiplie très facilement par bouture ?','La menthe','Le maïs','La carotte','Le radis',NULL,'A','La menthe','college',2,'⭐⭐ Moyen','Exact ! Un brin de menthe dans l\'eau fait vite des racines : c\'est une vivace facile à bouturer.','Exact ! Un brin de menthe dans l\'eau fait vite des racines : c\'est une vivace facile à bouturer.','Le maïs se sème par graine ; la menthe, elle, se bouture très facilement.',NULL,NULL,NULL,NULL,'bouture, vivace, multiplication',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0264','semis_recolte',8,'Récolter régulièrement des haricots ou des courgettes…','encourage la plante à produire davantage','arrête la production','tue la plante aussitôt','n\'a aucun effet',NULL,'A','encourage la plante à produire davantage','college',2,'⭐⭐ Moyen','Exact ! En récoltant souvent, on incite la plante à refaire des fleurs et des fruits.','Exact ! En récoltant souvent, on incite la plante à refaire des fleurs et des fruits.','C\'est l\'inverse : récolter régulièrement relance la production.',NULL,NULL,NULL,NULL,'récolte, floraison',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0265','semis_recolte',9,'Pourquoi démarrer certains semis en godet à l\'abri avant de les planter dehors ?','Pour les protéger du froid et leur donner une longueur d\'avance','Pour qu\'ils ne poussent jamais','Pour les empêcher de germer','Aucune raison',NULL,'A','Pour les protéger du froid et leur donner une longueur d\'avance','college',2,'⭐⭐ Moyen','Exact ! À l\'abri (au chaud), les jeunes plants démarrent tôt ; on les repique dehors une fois assez forts.','Exact ! À l\'abri (au chaud), les jeunes plants démarrent tôt ; on les repique dehors une fois assez forts.',NULL,'Au contraire, le godet à l\'abri favorise une bonne germination, il ne l\'empêche pas.',NULL,NULL,NULL,'semis, repiquage, germination',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0270','ravageurs_auxiliaires',5,'La cochenille s\'attaque aux plantes en…','suçant la sève, abritée sous une protection cireuse','mangeant les racines','creusant le sol','pollinisant les fleurs',NULL,'A','suçant la sève, abritée sous une protection cireuse','lycee',2,'⭐⭐ Moyen','Exact ! La cochenille est un insecte suceur ; sa carapace cireuse la protège, ce qui la rend tenace.','Exact ! La cochenille est un insecte suceur ; sa carapace cireuse la protège, ce qui la rend tenace.',NULL,NULL,'La cochenille n\'est pas un pollinisateur : c\'est un ravageur suceur de sève.',NULL,NULL,'cochenille, ravageur, herbivorie',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0271','ravageurs_auxiliaires',6,'Pourquoi voit-on souvent des fourmis près des colonies de pucerons ?','Les fourmis « élèvent » les pucerons pour leur miellat sucré','Les fourmis mangent les pucerons','Par hasard total','Les fourmis pollinisent les pucerons',NULL,'A','Les fourmis « élèvent » les pucerons pour leur miellat sucré','lycee',3,'⭐⭐⭐ Difficile','Exact ! Les fourmis protègent les pucerons et récoltent leur miellat : une relation mutuellement avantageuse (mutualisme).','Exact ! Les fourmis protègent les pucerons et récoltent leur miellat : une relation mutuellement avantageuse (mutualisme).','Au contraire, les fourmis protègent souvent les pucerons au lieu de les manger.',NULL,NULL,NULL,NULL,'fourmi, puceron, symbiose, mutualisme',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0272','ravageurs_auxiliaires',7,'Le phasme se protège de ses prédateurs surtout grâce…','au camouflage (il ressemble à une brindille)','à son venin','à sa vitesse','à sa carapace dure',NULL,'A','au camouflage (il ressemble à une brindille)','college',2,'⭐⭐ Moyen','Exact ! Le phasme imite une brindille : ce camouflage le rend presque invisible.','Exact ! Le phasme imite une brindille : ce camouflage le rend presque invisible.','Le phasme n\'a pas de venin : sa défense, c\'est le camouflage.',NULL,NULL,NULL,NULL,'phasme, camouflage, adaptation, prédation',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0273','ravageurs_auxiliaires',8,'Quel est l\'intérêt de la gambusie dans un bassin… et son revers ?','Elle mange les larves de moustiques, mais peut devenir invasive','Elle ne sert à rien','Elle pollinise les plantes','Elle fabrique de l\'azote',NULL,'A','Elle mange les larves de moustiques, mais peut devenir invasive','lycee',3,'⭐⭐⭐ Difficile','Exact ! Introduite contre les moustiques, la gambusie est efficace mais prolifère et menace la faune locale.','Exact ! Introduite contre les moustiques, la gambusie est efficace mais prolifère et menace la faune locale.','Elle a un rôle réel (manger des larves), mais attention : elle peut devenir une espèce invasive.',NULL,NULL,NULL,NULL,'gambusie, prédation, espèce invasive',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0280','eau_arrosage',3,'Où vaut-il mieux verser l\'eau quand on arrose ?','Au pied de la plante, près des racines','Sur les feuilles en plein soleil','Partout sauf sur la plante','Loin de la plante',NULL,'A','Au pied de la plante, près des racines','college',1,'⭐ Facile','Exact ! Arroser au pied envoie l\'eau directement aux racines et limite les maladies du feuillage.','Exact ! Arroser au pied envoie l\'eau directement aux racines et limite les maladies du feuillage.','Mouiller les feuilles en plein soleil favorise les maladies et gaspille l\'eau.',NULL,NULL,NULL,NULL,'arrosage, racine, eau',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0281','eau_arrosage',4,'Pourquoi récupérer l\'eau de pluie pour le jardin ?','C\'est une ressource gratuite qui économise l\'eau potable','La pluie est mauvaise pour les plantes','Pour la jeter ensuite','Cela n\'a aucun intérêt',NULL,'A','C\'est une ressource gratuite qui économise l\'eau potable','college',1,'⭐ Facile','Exact ! L\'eau de pluie est une ressource précieuse ; la récupérer s\'inscrit dans une gestion durable.','Exact ! L\'eau de pluie est une ressource précieuse ; la récupérer s\'inscrit dans une gestion durable.','Les plantes apprécient l\'eau de pluie : c\'est une excellente ressource.',NULL,NULL,NULL,NULL,'eau, ressource naturelle, développement durable, cycle de l\'eau',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0282','eau_arrosage',5,'Quel est un signe fréquent d\'un arrosage EXCESSIF d\'une plante en pot ?','Les racines pourrissent et les feuilles jaunissent','La plante grandit deux fois plus vite','Le sol devient sableux','Rien ne change jamais',NULL,'A','Les racines pourrissent et les feuilles jaunissent','lycee',2,'⭐⭐ Moyen','Exact ! Trop d\'eau asphyxie les racines (manque d\'air) : elles pourrissent et la plante dépérit.','Exact ! Trop d\'eau asphyxie les racines (manque d\'air) : elles pourrissent et la plante dépérit.','Trop d\'eau ne fait pas grandir plus vite : cela fait pourrir les racines.',NULL,NULL,NULL,NULL,'arrosage, drainage, racine',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0283','eau_arrosage',6,'Comment limiter l\'évaporation et les besoins en eau d\'un massif ?','En paillant le sol','En laissant le sol nu en plein soleil','En arrosant à midi','En bétonnant autour',NULL,'A','En paillant le sol','college',2,'⭐⭐ Moyen','Exact ! Le paillage garde l\'humidité ; combiné à un arrosage du matin, il réduit nettement les besoins en eau.','Exact ! Le paillage garde l\'humidité ; combiné à un arrosage du matin, il réduit nettement les besoins en eau.',NULL,'Arroser à midi gaspille l\'eau par évaporation : préférer le matin ou le soir.',NULL,NULL,NULL,'paillage, arrosage, eau',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0284','eau_arrosage',7,'Dans un sol argileux, l\'eau a tendance à…','rester longtemps (sol qui retient l\'eau)','s\'écouler aussitôt','disparaître dans l\'air','geler en été',NULL,'A','rester longtemps (sol qui retient l\'eau)','lycee',2,'⭐⭐ Moyen','Exact ! L\'argile retient l\'eau : un sol argileux se ressuie lentement, contrairement au sable qui draine vite.','Exact ! L\'argile retient l\'eau : un sol argileux se ressuie lentement, contrairement au sable qui draine vite.','C\'est le sol sableux qui draine vite ; l\'argile, elle, retient l\'eau.',NULL,NULL,NULL,NULL,'texture du sol, drainage, eau',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0290','energie_matiere',6,'L\'énergie d\'un écosystème provient à l\'origine…','du Soleil, captée par les plantes','du sol','des décomposeurs','des prédateurs',NULL,'A','du Soleil, captée par les plantes','lycee',2,'⭐⭐ Moyen','Exact ! La lumière solaire est captée par les producteurs (photosynthèse) : c\'est l\'entrée d\'énergie de l\'écosystème.','Exact ! La lumière solaire est captée par les producteurs (photosynthèse) : c\'est l\'entrée d\'énergie de l\'écosystème.','Le sol fournit l\'eau et les minéraux, mais l\'énergie vient du Soleil via les plantes.',NULL,NULL,NULL,NULL,'flux d\'énergie, photosynthèse, producteur',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0291','energie_matiere',7,'Pourquoi parle-t-on de production « secondaire » pour les animaux ?','C\'est la matière produite par les consommateurs à partir des producteurs','Parce qu\'ils produisent en deuxième','Parce qu\'ils font la photosynthèse','Cela ne veut rien dire',NULL,'A','C\'est la matière produite par les consommateurs à partir des producteurs','lycee',3,'⭐⭐⭐ Difficile','Exact ! La production primaire vient des plantes ; la production secondaire, c\'est la biomasse fabriquée par les consommateurs.','Exact ! La production primaire vient des plantes ; la production secondaire, c\'est la biomasse fabriquée par les consommateurs.',NULL,'Les animaux ne font pas de photosynthèse : ils transforment la matière des producteurs (production secondaire).',NULL,NULL,NULL,'production primaire, biomasse, niveau trophique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0300','cellule_metabolisme',6,'Les bactéries nitrifiantes fabriquent leur matière sans lumière, grâce à des réactions chimiques. On dit qu\'elles sont…','chimioautotrophes','carnivores','parasites','photosynthétiques',NULL,'A','chimioautotrophes','lycee',3,'⭐⭐⭐ Difficile','Exact ! Elles tirent leur énergie de l\'oxydation de l\'ammonium : c\'est la chimioautotrophie, sans lumière.','Exact ! Elles tirent leur énergie de l\'oxydation de l\'ammonium : c\'est la chimioautotrophie, sans lumière.',NULL,NULL,'Elles ne font pas de photosynthèse (pas de chlorophylle) : elles sont chimioautotrophes.',NULL,NULL,'chimioautotrophie, bactérie nitrifiante, autotrophe',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0301','cellule_metabolisme',7,'Quand une plante manque d\'oxygène à ses racines (sol détrempé), que se passe-t-il ?','Ses racines respirent mal et finissent par pourrir','Elle pousse plus vite','Elle fabrique plus de fleurs','Rien',NULL,'A','Ses racines respirent mal et finissent par pourrir','lycee',2,'⭐⭐ Moyen','Exact ! Les racines respirent : privées d\'oxygène dans un sol gorgé d\'eau, elles s\'asphyxient et pourrissent.','Exact ! Les racines respirent : privées d\'oxygène dans un sol gorgé d\'eau, elles s\'asphyxient et pourrissent.','Un excès d\'eau asphyxie les racines : la plante dépérit, elle ne pousse pas plus vite.',NULL,NULL,NULL,NULL,'respiration cellulaire, racine, drainage, dioxygène',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0310','evolution_biodiversite',7,'Pourquoi un champ d\'une seule variété (monoculture) est-il fragile ?','Peu de diversité génétique : une maladie peut tout ravager','Il pousse trop vite','Il attire trop d\'abeilles','Il n\'est pas fragile',NULL,'A','Peu de diversité génétique : une maladie peut tout ravager','lycee',3,'⭐⭐⭐ Difficile','Exact ! Sans diversité génétique, toutes les plantes sont sensibles aux mêmes maladies : le risque est maximal.','Exact ! Sans diversité génétique, toutes les plantes sont sensibles aux mêmes maladies : le risque est maximal.',NULL,NULL,'La monoculture est justement fragile, faute de diversité pour résister aux maladies.',NULL,NULL,'diversité génétique, biodiversité, résilience',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0320','populations_equilibres',7,'Le ver de terre, en creusant et brassant le sol, est qualifié d\'espèce…','ingénieure (il modifie le milieu pour d\'autres)','invasive','parasite','inutile',NULL,'A','ingénieure (il modifie le milieu pour d\'autres)','lycee',3,'⭐⭐⭐ Difficile','Exact ! En transformant physiquement le sol (galeries, brassage), le ver de terre crée des conditions favorables à d\'autres espèces.','Exact ! En transformant physiquement le sol (galeries, brassage), le ver de terre crée des conditions favorables à d\'autres espèces.',NULL,NULL,'Au contraire, le ver de terre est essentiel : c\'est une espèce ingénieure du sol.',NULL,NULL,'espèce ingénieure, sol vivant, ver de terre',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0330','agroecologie_permaculture',6,'Dans une forêt comestible, pourquoi superposer plusieurs « étages » de plantes ?','Pour occuper tout l\'espace et la lumière, comme une vraie forêt','Pour faire joli seulement','Pour gêner les plantes','Cela n\'a aucun intérêt',NULL,'A','Pour occuper tout l\'espace et la lumière, comme une vraie forêt','college',2,'⭐⭐ Moyen','Exact ! Arbres, arbustes, herbacées et couvre-sols se partagent lumière et espace : plus de production, moins d\'entretien.','Exact ! Arbres, arbustes, herbacées et couvre-sols se partagent lumière et espace : plus de production, moins d\'entretien.',NULL,'Bien pensées, les strates ne se gênent pas : elles se complètent comme dans une forêt.',NULL,NULL,NULL,'forêt comestible, permaculture, strates',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0331','agroecologie_permaculture',7,'L\'agroécologie cherche surtout à…','produire en s\'appuyant sur les équilibres naturels','remplacer la nature par des machines','utiliser un maximum de pesticides','supprimer la biodiversité',NULL,'A','produire en s\'appuyant sur les équilibres naturels','college',2,'⭐⭐ Moyen','Exact ! Sols vivants, biodiversité, recyclage de la matière : l\'agroécologie imite la nature plutôt que de la forcer.','Exact ! Sols vivants, biodiversité, recyclage de la matière : l\'agroécologie imite la nature plutôt que de la forcer.',NULL,'L\'agroécologie vise au contraire à réduire les pesticides en s\'appuyant sur les équilibres naturels.',NULL,NULL,NULL,'agroécologie, biodiversité, lutte biologique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0340','environnement_durable',6,'Le lombricomposteur permet, même en appartement, de…','recycler ses déchets de cuisine en engrais grâce aux vers','élever des poissons','fabriquer du plastique','produire de l\'électricité',NULL,'A','recycler ses déchets de cuisine en engrais grâce aux vers','college',1,'⭐ Facile','Exact ! Les vers transforment les épluchures en lombricompost riche : un geste durable, même sans jardin.','Exact ! Les vers transforment les épluchures en lombricompost riche : un geste durable, même sans jardin.','Le lombricomposteur sert à composter avec des vers, pas à élever des poissons.',NULL,NULL,NULL,NULL,'lombricompostage, recyclage, déchet organique',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
('QF0341','environnement_durable',7,'Pourquoi un excès d\'engrais azoté est-il un problème pour l\'environnement ?','Les nitrates lessivés polluent l\'eau et provoquent l\'eutrophisation','Cela fait pousser des arbres partout','Cela n\'a aucun effet','Cela nettoie les rivières',NULL,'A','Les nitrates lessivés polluent l\'eau et provoquent l\'eutrophisation','lycee',3,'⭐⭐⭐ Difficile','Exact ! L\'azote en excès est lessivé vers les eaux, où il fait proliférer les algues et asphyxie le milieu.','Exact ! L\'azote en excès est lessivé vers les eaux, où il fait proliférer les algues et asphyxie le milieu.',NULL,NULL,'C\'est l\'inverse : l\'excès d\'azote pollue et dégrade les milieux aquatiques.',NULL,NULL,'lessivage, eutrophisation, pollution, nitrate',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'actif','2026-06-16 19:37:33','2026-06-16 19:37:33'),
